class Playground {
    async run(inputs) {
        const numsStr = inputs[0] || "";
        const nums = numsStr.split(',').filter(x => x.trim() !== "").map(Number);

        // 1. Initialize data structures
        await this.nums.init(nums);
        await this.current_subset.init([]);
        await this.results.init([]);
        await this.callstack.init();
        await this.recursion_tree.init();

        const allSubsets = [];

        const backtrack = async (index, pathId) => {
            // Prepare unique ID for recursion tree node
            const currentPathStr = this.current_subset.getValues().join(',');
            const nodeId = `node-${index}-${pathId}`;

            // Mandatory Recursion Visuals
            this.callstack.pushFrame("backtrack", { index: index, path: `[${currentPathStr}]` });
            this.recursion_tree.enterNode(nodeId, `idx: ${index}`);

            this.log(`Processing index ${index}. Current path: [${currentPathStr}]`);
            if (index < nums.length) {
                this.nums.highlight(index, "#00e0ff");
            }
            await this.await();

            // Base Case: We've made a decision for all elements
            if (index === nums.length) {
                const subset = [...this.current_subset.getValues()];
                allSubsets.push(subset);
                this.results.push(`[${subset.join(',')}]`);
                this.log(`Reached leaf node. Adding subset [${subset.join(',')}] to results.`);

                await this.await();

                this.recursion_tree.exitNode("#00f5a0"); // Green for complete path
                this.callstack.popFrame();
                return;
            }

            const val = nums[index];

            // Decision 1: INCLUDE nums[index]
            this.log(`Decision: INCLUDE ${val}`);
            this.current_subset.push(val);
            await this.await();

            await backtrack(index + 1, pathId + "L");

            // BACKTRACK
            this.current_subset.pop();
            this.log(`Backtracking: Removed ${val} to explore next branch.`);
            await this.await();

            // Decision 2: EXCLUDE nums[index]
            this.log(`Decision: EXCLUDE ${val}`);
            await this.await();

            await backtrack(index + 1, pathId + "R");

            // Clean up visualization state
            this.nums.highlight(index, null);
            this.recursion_tree.exitNode();
            this.callstack.popFrame();
        };

        await backtrack(0, "root");

        this.log("Backtracking complete. All subsets found.");
        return allSubsets;
    }
}
